{
 "level": "B1",
 "intro": "In this topic, you will learn <strong>get-passive</strong>, the spoken version of the passive. It emphasizes a <strong>change of state, event or surprise</strong>, and often has an emotional tone.",
 "rules": [
 {
 "label": "Be Passive",
 "color": "blue",
 "text": "<strong>be + V3</strong> — neutral, formal:",
 "example": "He was fired last week."
 },
 {
 "label": "Get Passive",
 "color": "emerald",
 "text": "<strong>get + V3</strong> — conversational, dynamic:",
 "example": "He got fired last week."
 },
 {
 "label": "Shade",
 "color": "rose",
 "text": "Get-passive = event, change, surprise:",
 "example": "They got married in June."
 }
 ]
}

{
 "title": "1. Get-passive structure",
 "intro": "Formula: <strong>get + Past Participle (V3)</strong>",
 "items": [
 {
 "label": "Formula",
 "title": "get + V3",
 "subtitle": "get instead of be in the passive"
 },
 {
 "label": "times",
 "title": "get varies by time",
 "subtitle": "get/gets/got/will get/getting + V3"
 },
 {
 "label": "Style",
 "title": "Talkative, informal",
 "subtitle": "More often in spoken English"
 },
 {
 "label": "Shade",
 "title": "Event, change of state",
 "subtitle": "Something happened (often unexpectedly)"
 }
 ]
}

{
 "title": "2. When to use Get-passive?",
 "sections": [
 {
 "label": "Unexpected events",
 "color": "emerald",
 "description": "When something <strong>happened unexpectedly</strong>, accidentally.",
 "examples": [
 {
 "en": "He got hit by a car.",
 "ua": "He got hit by a car."
 },
 {
 "en": "She got caught in the rain.",
 "ua": "She got caught in the rain."
 },
 {
 "en": "I got stuck in traffic.",
 "ua": "I got stuck in traffic."
 }
 ]
 },
 {
 "label": "Negative events",
 "color": "rose",
 "description": "Often for <strong>negative, unpleasant</strong> situations.",
 "examples": [
 {
 "en": "He got fired from his job.",
 "ua": "He got fired from his job."
 },
 {
 "en": "She got hurt in the accident.",
 "ua": "She got hurt in the accident."
 },
 {
 "en": "My phone got stolen.",
 "ua": "My phone got stolen."
 }
 ]
 },
 {
 "label": "Change of state",
 "color": "sky",
 "description": "Emphasizes the <strong>transition from one state to another</strong>.",
 "examples": [
 {
 "en": "They got married last year.",
 "ua": "They got married last year."
 },
 {
 "en": "He got promoted to manager.",
 "ua": "He got promoted to manager."
 },
 {
 "en": "The window got broken.",
 "ua": "The window got broken."
 }
 ]
 },
 {
 "label": "Positive events",
 "color": "amber",
 "description": "Sometimes for <strong>positive changes</strong> — but less often.",
 "examples": [
 {
 "en": "She got accepted to university.",
 "ua": "She got accepted to university."
 },
 {
 "en": "He got selected for the team.",
 "ua": "He got selected for the team."
 },
 {
 "en": "I got invited to the party.",
 "ua": "I got invited to the party."
 }
 ]
 }
 ]
}

{
 "title": "3. Typical expressions with Get-passive",
 "sections": [
 {
 "label": "Personal life",
 "color": "emerald",
 "description": "Expressions about <strong>personal events and relationships</strong>.",
 "examples": [
 {
 "en": "get married",
 "ua": "get married"
 },
 {
 "en": "get divorced",
 "ua": "get divorced"
 },
 {
 "en": "get engaged",
 "ua": "get engaged"
 }
 ]
 },
 {
 "label": "Work",
 "color": "blue",
 "description": "Expressions about <strong>work and career</strong>.",
 "examples": [
 {
 "en": "get hired",
 "ua": "get hired"
 },
 {
 "en": "get fired",
 "ua": "get fired"
 },
 {
 "en": "get promoted",
 "ua": "get promoted"
 },
 {
 "en": "get paid",
 "ua": "get paid"
 }
 ]
 },
 {
 "label": "Troubles",
 "color": "rose",
 "description": "Expressions about <strong>problems and troubles</strong>.",
 "examples": [
 {
 "en": "get hurt",
 "ua": "get hurt"
 },
 {
 "en": "get injured",
 "ua": "get injured"
 },
 {
 "en": "get lost",
 "ua": "get lost"
 },
 {
 "en": "get stuck",
 "ua": "get stuck"
 }
 ]
 },
 {
 "label": "Other situations",
 "color": "amber",
 "description": "Other <strong>regular expressions</strong> with get-passive.",
 "examples": [
 {
 "en": "get caught",
 "ua": "get caught"
 },
 {
 "en": "get arrested",
 "ua": "get arrested"
 },
 {
 "en": "get killed",
 "ua": "get killed"
 },
 {
 "en": "get dressed",
 "ua": "get dressed"
 }
 ]
 }
 ]
}

{
 "title": "4. Get-passive in different tenses",
 "sections": [
 {
 "label": "Present Simple",
 "color": "emerald",
 "description": "<strong>get/gets + V3</strong> — regular actions, habits.",
 "examples": [
 {
 "en": "He often gets invited to parties.",
 "ua": "He often gets invited to parties."
 },
 {
 "en": "People get hurt in accidents every day.",
 "ua": "People get hurt in accidents every day."
 }
 ]
 },
 {
 "label": "Past Simple",
 "color": "blue",
 "description": "<strong>got + V3</strong> — specific events in the past.",
 "examples": [
 {
 "en": "She got promoted last month.",
 "ua": "She got promoted last month."
 },
 {
 "en": "They got married in 2020.",
 "ua": "They got married in 2020."
 }
 ]
 },
 {
 "label": "Future",
 "color": "sky",
 "description": "<strong>will get + V3</strong> / <strong>be going to get + V3</strong>.",
 "examples": [
 {
 "en": "She will get paid tomorrow.",
 "ua": "She will get paid tomorrow."
 },
 {
 "en": "He is going to get fired if he is late again.",
 "ua": "He is going to get fired if he is late again."
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "amber",
 "description": "<strong>have/has got + V3</strong> is the result so far.",
 "examples": [
 {
 "en": "She has got accepted to Harvard!",
 "ua": "She has got accepted to Harvard!"
 },
 {
 "en": "I have got stuck in this traffic for an hour.",
 "ua": "I have got stuck in this traffic for an hour."
 }
 ]
 }
 ]
}

{
 "title": "5. Be Passive vs Get Passive",
 "intro": "Comparison of standard passive with get-passive:",
 "rows": [
 {
 "en": "be + V3",
 "ua": "be + V3",
 "note": "The report was completed."
 },
 {
 "en": "get + V3",
 "ua": "get + V3",
 "note": "The report got completed."
 },
 {
 "en": "be + V3",
 "ua": "be + V3",
 "note": "The door is closed. (flat rate)"
 },
 {
 "en": "get + V3",
 "ua": "get + V3",
 "note": "The door got closed. (action, event)"
 },
 {
 "en": "be + V3",
 "ua": "be + V3",
 "note": "It always fits."
 },
 {
 "en": "get + V3",
 "ua": "get + V3",
 "note": "Often negative, unexpected."
 }
 ],
 "warning": "📌 <strong>Get-passive</strong> more often for unexpected, negative or dynamic events!"
}

{
 "title": "6. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Using get-passive in a formal context.",
 "wrong": "The contract got signed by the CEO. (formal)",
 "right": "✅ The contract was signed by the CEO."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Confusion of get + adjective vs get + V3.",
 "wrong": "I got interesting.",
 "right": "✅ I got interested in the topic."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using be instead of get to change state.",
 "wrong": "They were married last June.",
 "right": "✅ They got married last June."
 }
 ]
}
